"import sys

with open("src/components/SettingsPortal.tsx", "rb") as f:
    content = f.read()

for line in content.split(b"\n"):
    if b"throw new Error" in line and b"Facebook" in line:
        print("Line:", line)
        print("Bytes:", list(line))
        try:
            m = line.split(b"'")
            if len(m) > 1:
                corrupted_str = m[1].decode('utf-8')
                print("Corrupted string:", corrupted_str)
                # Try to encode/decode
                for enc in ['utf-8', 'latin-1', 'windows-1252', 'cp874']:
                    for dec in ['utf-8', 'latin-1', 'windows-1252', 'cp874']:
                        try:
                            # Let's try encode(enc).decode(dec) or other combinations
                            # Some tools treat UTF-8 as Latin-1 when reading, then write it out as UTF-8
                            # That means we need to encode as utf-8, then decode as latin-1 or vice-versa
                            b = corrupted_str.encode(enc)
                            s = b.decode(dec)
                            if 'เกิด' in s:
                                print(f"SUCCESS: encode={enc}, decode={dec} -> {s}")
                        except:
                            pass
        except Exception as e:
            print("Error:", e)
        break
"
